INSERT INTO Blog (title, content, image, author, tags, createdAt, updatedAt) VALUES 
('أسرار السفر إلى المالديف: كيف تختار جزيرتك المثالية؟', 'تعتبر جزر المالديف جنة الله على الأرض، ولكن هل كنت تعلم أن اختيار المنتجع الصحيح قد يغير تجربة سفرك بالكامل؟\n\nفي الميراج، قمنا بزيارة أكثر من 50 منتجعاً لنقدم لك هذا الدليل الحصري:\n\n1. **المنتجات الصديقة للبيئة**: إذا كنت تبحث عن الهدوء والارتباط بالطبيعة.\n2. **جزر العائلات**: منتجعات تضم نوادي للأطفال وأنشطة مائية متنوعة.\n3. **الفلل العائمة فوق الماء**: الخيار الأمثل لقضاء شهر عسل رومانسي.\n\nنصيحة الميراج: أفضل وقت للزيارة هو بين شهري ديسمبر وأبريل حيث تكون الأجواء صافية تماماً والمياه في أقصى درجات شفافيتها.', 'https://images.unsplash.com/photo-1514282401047-d79a71a590e8?q=80&w=1200&auto=format&fit=crop', 'مستشار السفر الملكي', 'المالديف, نصائح سفر, شهر عسل', NOW(), NOW()),
('دليل الميراج السياحي: أفضل المدن الأوروبية لعام 2026', 'أوروبا تتجدد دائماً، وفي عام 2026 تبرز وجهات جديدة بجانب العواصم الكلاسيكية:\n\n- **براغ، التشيك**: لؤلؤة العصور الوسطى التي تأخذك في رحلة عبر الزمن.\n- **لشبونة، البرتغال**: مزيج فريد من التاريخ، الفن، والطعام البحري المذهل.\n- **إنترلاكن، سويسرا**: لعشاق المناظر الجبلية والبحيرات الفيروزية.\n\nلماذا تحجز مع الميراج؟ لأننا نوفر لك مرشدين يتحدثون العربية في جميع هذه المدن لضمان راحتك التامة.', 'https://images.unsplash.com/photo-1467269204594-9661b134dd2b?q=80&w=1200&auto=format&fit=crop', 'فريق التخطيط السياحي', 'أوروبا, سياحة عالمية, 2026', NOW(), NOW()),
('سحر الشرق: لماذا يجب أن تكون اليابان وجهتك القادمة؟', 'اليابان ليست مجرد دولة، بل هي كوكب آخر يجمع بين التكنولوجيا الفائقة والتقاليد العريقة.\n\n- **طوكيو**: المدينة التي لا تنام أبداً.\n- **كيوتو**: حيث تجد المعابد البوذية والحدائق اليابانية الهادئة.\n- **أوساكا**: عاصمة المطبخ الياباني التي ستدهشك بنكهاتها.\n\nنحن في الميراج نضمن لك تجربة يابانية أصيلة من خلال ترتيب إقامات في فنادق "الريوكان" التقليدية وتذاكر القطار الطلقة السريع.', 'https://images.unsplash.com/photo-1493976040374-85c8e12f0c0e?q=80&w=1200&auto=format&fit=crop', 'قسم الرحلات الآسيوية', 'اليابان, ثقافة, مغامرة', NOW(), NOW());
INSERT INTO Package (title, description, image, price, oldPrice, discount, duration, location, category, isFeatured, createdAt, updatedAt) VALUES 
('باقة المالديف الملكية - منتجع فور سيزونز', 'استمتع بإقامة فاخرة لمدة 6 أيام في فيلا عائمة فوق الماء مع مسبح خاص. تشمل الباقة وجبات الإفطار والعشاء، رحلة صيد وقت الغروب، وجلسة تدليك مجانية لشخصين.', 'https://images.unsplash.com/photo-1506953823976-52e1fdc0149a?q=80&w=1200&auto=format&fit=crop', 15500, 18000, 15, '6 أيام / 5 ليالي', 'المالديف', 'packages', 1, NOW(), NOW()),
('جولة في التاريخ العثماني - إسطنبول وبورصة', 'اكتشف عراقة التاريخ في أجمل مدن تركيا. جولة سياحية شاملة تغطي أهم المعالم التاريخية مع إقامة في فنادق 5 نجوم ووجبات تركية أصيلة.', 'https://images.unsplash.com/photo-1524231757912-21f4fe3a7200?q=80&w=1200&auto=format&fit=crop', 4200, 5000, 16, '8 أيام / 7 ليالي', 'تركيا', 'packages', 1, NOW(), NOW()),
('عرض العمرة الفاخر - فندق دار التوحيد', 'نقدم لك تجربة روحانية استثنائية مع إقامة في أقرب الفنادق للحرم المكي الشريف. تشمل الباقة الاستقبال والتوديع في المطار بسيارات حديثة.', 'https://images.unsplash.com/photo-1591604129939-f1efa4d9f7fa?q=80&w=1200&auto=format&fit=crop', 5500, 6500, 15, '5 أيام / 4 ليالي', 'السعودية', 'umrah', 1, NOW(), NOW());
